import React, { useState, useRef, useMemo, useEffect, useCallback } from "react";
import { motion } from "framer-motion";
import { ChevronLeft, ChevronRight } from "lucide-react";
import "./Products.css";

const Products = () => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const scrollRef = useRef(null);
  const [showForm, setShowForm] = useState(false);
  const [showDetails, setShowDetails] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [selectedForDetails, setSelectedForDetails] = useState(null);

  // ──────────────────────────────────────────────────────────────
  //  NODE ENDPOINTS
  // ──────────────────────────────────────────────────────────────
  const API_URL = "http://localhost:5000/api/getData";          // ← NEW
  const IMAGE_BASE = "http://localhost:5000";                  // ← NEW
  const QUOTE_URL = "http://localhost:5000/api/sendQuote";     // ← NEW
  // ──────────────────────────────────────────────────────────────

  useEffect(() => {
    fetch(API_URL)
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(fetchedData => {
        console.log("Fetched Data:", fetchedData);
        setData(fetchedData);
      })
      .catch(err => {
        console.error("Fetch error:", err);
        alert("Failed to load products: " + err.message);
      })
      .finally(() => setLoading(false));
  }, []);

  // Filter out null subProducts
  const categories = useMemo(() =>
    data?.categories?.map(cat => ({
      ...cat,
      subProducts: (cat.subProducts || []).filter(Boolean)
    })) || [], [data]
  );

  const { description = "" } = data?.companyInfo || {};
  const products = useMemo(() => categories, [categories]);

  // Full image URL
  const getImageUrl = useCallback((img) => {
    if (!img) return "";
    return img.startsWith("http") ? img : `${IMAGE_BASE}/${img}`;
  }, [IMAGE_BASE]);

  // Scroll buttons
  const scroll = useCallback((direction) => {
    if (scrollRef.current) {
      const amount = 300;
      scrollRef.current.scrollBy({
        left: direction === "left" ? -amount : amount,
        behavior: "smooth",
      });
    }
  }, []);

  // Search filter
  const filteredProducts = useMemo(() =>
    products.filter(p =>
      p.category?.toLowerCase().includes(searchTerm.toLowerCase())
    ), [products, searchTerm]
  );

  const categoriesList = useMemo(() =>
    [...new Set(filteredProducts.map(p => p.category))], [filteredProducts]
  );

  const featuredCategories = useMemo(() => categoriesList, [categoriesList]);

  const activeSubProducts = useMemo(() => {
    if (!activeCategory) return [];
    return products.find(p => p.category === activeCategory)?.subProducts || [];
  }, [products, activeCategory]);

  const handleQuote = useCallback((product) => {
    setSelectedProduct(product);
    setShowForm(true);
  }, []);

  const handleDetails = useCallback((product) => {
    setSelectedForDetails(product);
    setShowDetails(true);
  }, []);

  const handleCustomQuote = useCallback(() => {
    setSelectedProduct({ name: "Custom Solution" });
    setShowForm(true);
  }, []);

  // ──────────────────────────────────────────────────────────────
  //  RENDER
  // ──────────────────────────────────────────────────────────────
  if (loading) return <div className="py-12 text-center">Loading products...</div>;
  if (!data || data.error) return <div className="py-12 text-center">No data available. {data?.error}</div>;

  return (
    <section id="products" className="py-12 text-gray-800 sm:py-20 bg-gray-50">
      <div className="px-4 mx-auto max-w-7xl">
        <motion.h2
          className="mb-6 text-3xl font-bold text-center text-blue-700 sm:text-5xl sm:mb-10"
          initial={{ y: -50 }}
          whileInView={{ y: 0 }}
          viewport={{ once: true }}
        >
          Our Products & Services
        </motion.h2>

        <p className="max-w-3xl mx-auto mb-8 text-lg text-center text-gray-600">
          {description}
        </p>

        {/* Categories Scroll */}
        <div className="relative mb-10" role="navigation" aria-label="Product categories">
          <button
            onClick={() => scroll("left")}
            className="absolute left-0 p-2 text-blue-600 -translate-y-1/2 rounded-full top-1/2 scroll-arrow hover:bg-blue-100"
            aria-label="Scroll left"
          >
            <ChevronLeft size={24} />
          </button>

          <div
            ref={scrollRef}
            className="flex gap-3 px-10 overflow-x-auto products-scroll no-scrollbar"
            style={{ scrollbarWidth: "none", msOverflowStyle: "none" }}
          >
            <motion.button
              onClick={() => setActiveCategory(null)}
              className={`px-6 py-3 rounded-full font-semibold transition flex-shrink-0 ${
                !activeCategory ? "bg-blue-600 text-white" : "bg-white text-blue-700 border border-blue-300"
              }`}
              whileHover={{ scale: 1.05 }}
              aria-pressed={!activeCategory}
            >
              All Categories
            </motion.button>

            {categoriesList.map((cat, i) => (
              <motion.button
                key={i}
                onClick={() => setActiveCategory(cat)}
                className={`px-6 py-3 rounded-full font-semibold transition flex-shrink-0 ${
                  activeCategory === cat ? "bg-blue-600 text-white" : "bg-white text-blue-700 border border-blue-300"
                }`}
                whileHover={{ scale: 1.05 }}
                aria-pressed={activeCategory === cat}
              >
                {cat}
              </motion.button>
            ))}
          </div>

          <button
            onClick={() => scroll("right")}
            className="absolute right-0 p-2 text-blue-600 -translate-y-1/2 rounded-full top-1/2 scroll-arrow hover:bg-blue-100"
            aria-label="Scroll right"
          >
            <ChevronRight size={24} />
          </button>
        </div>

        {/* Featured or Sub-Products */}
        <motion.div
          className="grid gap-6 lg:grid-cols-4"
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          transition={{ staggerChildren: 0.1 }}
          viewport={{ once: true }}
        >
          {!activeCategory ? (
            featuredCategories.length === 0 ? (
              <div className="py-8 text-center col-span-full">
                <p className="text-gray-500">No categories found.</p>
              </div>
            ) : (
              featuredCategories.slice(0, 12).map((cat) => {
                const catData = products.find(p => p.category === cat);
                const subProducts = catData?.subProducts || [];
                const firstImg = subProducts[0]?.images?.[0];
                return (
                  <FeaturedCategoryCard
                    key={cat}
                    category={cat}
                    subProducts={subProducts}
                    imageSrc={firstImg ? getImageUrl(firstImg) : null}
                    onViewAll={() => setActiveCategory(cat)}
                  />
                );
              })
            )
          ) : (
            activeSubProducts.length === 0 ? (
              <div className="py-8 text-center col-span-full">
                <p className="text-gray-500">No products found.</p>
              </div>
            ) : (
              <div className="lg:col-span-full lg:grid lg:grid-cols-3 lg:gap-6">
                {activeSubProducts.map((sub, i) => (
                  <ProductCard
                    key={i}
                    name={sub.name}
                    price={sub.price}
                    images={sub.images || []}
                    description={sub.description}
                    specs={sub.specs || []}
                    additionalInfo={sub.additionalInfo || {}}
                    onQuote={() => handleQuote(sub)}
                    onDetails={() => handleDetails(sub)}
                    getImageUrl={getImageUrl}
                  />
                ))}
              </div>
            )
          )}
        </motion.div>

        <div className="mt-12 text-center">
          <button
            onClick={handleCustomQuote}
            className="inline-block px-8 py-4 text-lg font-semibold text-white transition-colors bg-blue-600 rounded-full hover:bg-blue-700"
          >
            Enquire for Custom Solutions
          </button>
        </div>
      </div>

      {/* Quote Modal */}
      {showForm && (
        <QuoteForm
          product={selectedProduct}
          onClose={() => setShowForm(false)}
          quoteUrl={QUOTE_URL}
        />
      )}

      {/* Details Modal */}
      {showDetails && (
        <ProductDetails
          product={selectedForDetails}
          onClose={() => setShowDetails(false)}
          getImageUrl={getImageUrl}
        />
      )}
    </section>
  );
};

// ──────────────────────────────────────────────────────────────
//  COMPONENTS (unchanged logic, just props updated)
// ──────────────────────────────────────────────────────────────
const FeaturedCategoryCard = React.memo(({ category, subProducts, imageSrc, onViewAll }) => (
  <motion.div
    className="flex flex-col bg-white border border-gray-200 shadow-lg rounded-xl"
    whileHover={{ y: -5 }}
  >
    <div className="relative h-48 mb-4 overflow-hidden rounded-t-xl">
      {imageSrc ? (
        <img src={imageSrc} alt={`${category} preview`} className="object-cover w-full h-full" loading="lazy" />
      ) : (
        <div className="flex items-center justify-center w-full h-full bg-gray-100 rounded-t-xl">
          <span className="text-gray-500">Category Preview</span>
        </div>
      )}
    </div>
    <div className="flex flex-col flex-grow p-6">
      <h3 className="mb-4 text-xl font-bold text-gray-900">{category}</h3>
      {subProducts.length > 0 && (
        <ul className="flex-grow mb-4 space-y-2 text-sm text-gray-600">
          {subProducts.slice(0, 4).map((s, i) => (
            <li key={i}>• {s.name}</li>
          ))}
          {subProducts.length > 4 && <li className="text-gray-400">...and more</li>}
        </ul>
      )}
      <button
        onClick={onViewAll}
        className="self-start px-4 py-2 font-medium text-blue-600 border border-blue-300 rounded hover:bg-blue-50"
      >
        + View All
      </button>
    </div>
  </motion.div>
));

const ProductCard = React.memo(({ name, price, images = [], description, specs = [], additionalInfo = {}, onQuote, onDetails, getImageUrl }) => (
  <motion.div
    className="flex flex-col p-6 bg-white border border-gray-200 shadow-lg rounded-xl hover:shadow-xl"
    whileHover={{ y: -5 }}
  >
    <div className="relative h-48 mb-4 overflow-hidden rounded-lg">
      {images[0] ? (
        <>
          <img src={getImageUrl(images[0])} alt={`${name} preview`} className="object-cover w-full h-full" loading="lazy" />
          {images.length > 1 && (
            <div className="absolute px-2 py-1 text-xs text-white bg-blue-600 rounded-full top-2 right-2">
              +{images.length - 1}
            </div>
          )}
        </>
      ) : (
        <div className="flex items-center justify-center w-full h-full bg-gray-100 rounded">
          <span className="text-gray-500">Product Preview</span>
        </div>
      )}
    </div>
    <h3 className="mb-2 text-xl font-bold text-gray-900">{name}</h3>
    {price && <p className="mb-2 text-lg font-semibold text-green-600">{price}</p>}
    {description && <p className="mb-4 text-sm text-gray-600 line-clamp-2">{description}</p>}
    {(specs.length > 0 || Object.keys(additionalInfo).length > 0) && (
      <div className="mb-4 space-y-1 text-xs text-gray-500">
        {specs.slice(0, 2).map((s, i) => (
          <p key={i}><strong>{s.key}:</strong> {s.value}</p>
        ))}
        {Object.entries(additionalInfo).slice(0, 1).map(([k, v]) => (
          <p key={k}><strong>{k}:</strong> {v}</p>
        ))}
      </div>
    )}
    <div className="flex mt-auto space-x-2">
      <button onClick={onQuote} className="flex-1 px-4 py-2 text-white bg-blue-600 rounded hover:bg-blue-700">
        Get Quote
      </button>
      <button onClick={onDetails} className="flex-1 px-4 py-2 text-gray-700 bg-gray-200 rounded hover:bg-gray-300">
        Product Details
      </button>
    </div>
  </motion.div>
));

const ProductDetails = ({ product, onClose, getImageUrl }) => {
  const [idx, setIdx] = useState(0);
  if (!product) return null;
  const total = product.images?.length || 1;

  const next = () => setIdx((i) => (i + 1) % total);
  const prev = () => setIdx((i) => (i - 1 + total) % total);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" role="dialog" aria-modal="true">
      <motion.div
        className="relative w-full max-w-2xl p-6 bg-white shadow-lg rounded-xl max-h-[90vh] overflow-y-auto"
        initial={{ scale: 0.95 }} animate={{ scale: 1 }} exit={{ scale: 0.95 }}
      >
        <button onClick={onClose} className="absolute text-gray-500 top-3 right-3 hover:text-gray-800">X</button>
        <h3 className="mb-4 text-2xl font-bold text-blue-700">{product.name}</h3>
        {product.price && <p className="mb-4 text-lg font-semibold text-green-600">Price: {product.price}</p>}

        <div className="relative mb-4">
          <div className="relative h-64 overflow-hidden rounded-lg">
            {product.images?.[idx] ? (
              <motion.img
                key={idx}
                src={getImageUrl(product.images[idx])}
                alt={`${product.name} ${idx + 1}`}
                className="object-cover w-full h-full"
                initial={{ x: 50 }} animate={{ x: 0 }} transition={{ duration: 0.3 }}
                loading="lazy"
              />
            ) : (
              <div className="flex items-center justify-center w-full h-64 bg-gray-100 rounded-lg">
                <span className="text-gray-500">Product Preview</span>
              </div>
            )}
            {total > 1 && (
              <>
                <button onClick={prev} className="absolute p-2 -translate-y-1/2 rounded-full shadow-md left-2 top-1/2 bg-white/80">
                  <ChevronLeft size={20} />
                </button>
                <button onClick={next} className="absolute p-2 -translate-y-1/2 rounded-full shadow-md right-2 top-1/2 bg-white/80">
                  <ChevronRight size={20} />
                </button>
                <div className="absolute flex space-x-2 -translate-x-1/2 bottom-2 left-1/2">
                  {product.images?.map((_, i) => (
                    <button
                      key={i}
                      onClick={() => setIdx(i)}
                      className={`w-2 h-2 rounded-full ${i === idx ? "bg-blue-600" : "bg-gray-300"}`}
                    />
                  ))}
                </div>
              </>
            )}
          </div>
          {total > 1 && <p className="mt-2 text-sm text-center text-gray-500">{idx + 1} / {total}</p>}
        </div>

        {product.description && (
          <div className="mb-4">
            <h4 className="mb-2 font-medium text-gray-700">Description:</h4>
            <p className="text-gray-600">{product.description}</p>
          </div>
        )}
        {product.specs?.length > 0 && (
          <div className="mb-4">
            <h4 className="mb-2 font-medium text-gray-700">Key Specs:</h4>
            <ul className="space-y-1 text-sm text-gray-500">
              {product.specs.map((s, i) => (
                <li key={i}><strong>{s.key}:</strong> {s.value}</li>
              ))}
            </ul>
          </div>
        )}
        {Object.keys(product.additionalInfo || {}).length > 0 && (
          <div className="mb-4">
            <h4 className="mb-2 font-medium text-gray-700">Additional Info:</h4>
            <ul className="space-y-1 text-sm text-gray-500">
              {Object.entries(product.additionalInfo).map(([k, v]) => (
                <li key={k}><strong>{k}:</strong> {v}</li>
              ))}
            </ul>
          </div>
        )}
      </motion.div>
    </div>
  );
};

// ──────────────────────────────────────────────────────────────
//  QUOTE FORM – NOW POSTS TO NODE
// ──────────────────────────────────────────────────────────────
const QuoteForm = ({ product, onClose, quoteUrl }) => {
  const [form, setForm] = useState({ name: "", email: "", phone: "", details: "" });
  const firstInputRef = useRef(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");
    try {
      const res = await fetch(quoteUrl, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          product: product?.name,
          name: form.name,
          email: form.email,
          mobile: form.phone,    // backend expects `mobile`
          message: form.details, // backend expects `message`
        }),
      });

      const data = await res.json().catch(() => ({}));

      if (data.success || data.ok || res.ok) {
        setSuccess(true);
        setForm({ name: "", email: "", phone: "", details: "" });
        // keep success visible briefly then close
        setTimeout(() => {
          setSuccess(false);
          onClose();
        }, 1400);
      } else {
        throw new Error(data.error || data.message || 'Submission failed');
      }
    } catch (err) {
      setError(err.message || String(err));
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (field) => (e) => setForm({ ...form, [field]: e.target.value });

  // Focus the first input when the modal mounts so users can type immediately
  useEffect(() => {
    try {
      firstInputRef.current?.focus();
    } catch (e) {
      /* ignore focus errors */
    }
  }, []);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" role="dialog" aria-modal="true">
      <motion.div
        className="relative w-full max-w-md p-6 bg-white shadow-lg rounded-xl"
        initial={{ scale: 0.95 }} animate={{ scale: 1 }} exit={{ scale: 0.95 }}
      >
        <button onClick={onClose} className="absolute text-gray-500 top-3 right-3 hover:text-gray-800">X</button>
        <h3 className="mb-4 text-2xl font-bold text-blue-700">
          Get Quote for {product?.name}
        </h3>
        <form onSubmit={handleSubmit} className="space-y-4">
          <input name="name" ref={firstInputRef} type="text" placeholder="Your Name" value={form.name} onChange={handleChange("name")} required autoComplete="name" className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-300" />
          <input name="email" type="email" placeholder="Your Email" value={form.email} onChange={handleChange("email")} required autoComplete="email" className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-300" />
          <input name="mobile" type="tel" placeholder="Mobile Number" value={form.phone} onChange={handleChange("phone")} required autoComplete="tel" className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-300" />
          <textarea name="message" placeholder="Work Details" value={form.details} onChange={handleChange("details")} rows={3} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-300" />
          {error && <p className="text-sm text-red-500">{error}</p>}
          {success && <p className="text-sm text-green-600">Message sent successfully!</p>}
          <button
            type="submit"
            disabled={loading}
            className="w-full py-2 text-white bg-blue-600 rounded-lg hover:bg-blue-700 disabled:opacity-50"
          >
            {loading ? "Sending..." : "Submit Request"}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

export default Products;
